1	// Named in-memory repositories — the fallback used when DATABASE_URL is unset so
2	// the app runs on a clean checkout (TC-DATA-01). They implement the same domain
3	// repository ports as the postgres-backed repositories.
4	
5	import type { Account } from "@/src/domain/account";
6	import type { InputEvent, NewInputEvent } from "@/src/domain/input-event";
7	import type { LedgerItem } from "@/src/domain/ledger-item";
8	import type { NewParserRun, ParserRun } from "@/src/domain/parser-run";
9	import type {
10	  AccountRepository,
11	  InputEventRepository,
12	  LedgerItemRepository,
13	  ParserRunRepository,
14	  Repositories,
15	} from "@/src/domain/ports";
16	
17	function newId(): string {
18	  return globalThis.crypto.randomUUID();
19	}
20	
21	class MemoryAccountRepository implements AccountRepository {
22	  private readonly store = new Map<string, Account>();
23	
24	  private active(): Account[] {
25	    return [...this.store.values()].filter((a) => a.archivedAt === null);
26	  }
27	
28	  async list(opts?: { includeArchived?: boolean }): Promise<Account[]> {
29	    const all = [...this.store.values()];
30	    return (opts?.includeArchived ? all : all.filter((a) => a.archivedAt === null)).map(
31	      (a) => ({ ...a }),
32	    );
33	  }
34	
35	  async findById(id: string): Promise<Account | null> {
36	    const found = this.store.get(id);
37	    return found ? { ...found } : null;
38	  }
39	
40	  async findDefault(): Promise<Account | null> {
41	    const found = this.active().find((a) => a.isDefault);
42	    return found ? { ...found } : null;
43	  }
44	
45	  async countActive(): Promise<number> {
46	    return this.active().length;
47	  }
48	
49	  async insert(account: Account): Promise<Account> {
50	    this.store.set(account.id, { ...account });
51	    return { ...account };
52	  }
53	
54	  async update(account: Account): Promise<Account> {
55	    this.store.set(account.id, { ...account });
56	    return { ...account };
57	  }
58	
59	  async setDefault(id: string): Promise<void> {
60	    for (const [key, account] of this.store) {
61	      if (account.isDefault) this.store.set(key, { ...account, isDefault: false });
62	    }
63	    const target = this.store.get(id);
64	    if (target) this.store.set(id, { ...target, isDefault: true });
65	  }
66	}
67	
68	class MemoryInputEventRepository implements InputEventRepository {
69	  private readonly store = new Map<string, InputEvent>();
70	
71	  async create(event: NewInputEvent): Promise<InputEvent> {
72	    const created: InputEvent = {
73	      id: event.id ?? newId(),
74	      source: event.source,
75	      provider: event.provider,
76	      rawText: event.rawText,
77	      storageUri: event.storageUri,
78	      mimeType: event.mimeType,
79	      createdAt: new Date(),
80	    };
81	    this.store.set(created.id, created);
82	    return created;
83	  }
84	
85	  async findById(id: string): Promise<InputEvent | null> {
86	    return this.store.get(id) ?? null;
87	  }
88	}
89	
90	class MemoryParserRunRepository implements ParserRunRepository {
