32	class PgAccountRepository implements AccountRepository {
33	  constructor(private readonly sql: Sql) {}
34	
35	  async list(opts?: { includeArchived?: boolean }): Promise<Account[]> {
36	    const rows = opts?.includeArchived
37	      ? await this.sql<AccountRow[]>`SELECT * FROM accounts ORDER BY created_at`
38	      : await this.sql<AccountRow[]>`
39	          SELECT * FROM accounts WHERE archived_at IS NULL ORDER BY created_at`;
40	    return rows.map(toAccount);
41	  }
42	
43	  async findById(id: string): Promise<Account | null> {
44	    const [row] = await this.sql<AccountRow[]>`
45	      SELECT * FROM accounts WHERE id = ${id}`;
46	    return row ? toAccount(row) : null;
47	  }
48	
49	  async findDefault(): Promise<Account | null> {
50	    const [row] = await this.sql<AccountRow[]>`
51	      SELECT * FROM accounts WHERE archived_at IS NULL AND is_default LIMIT 1`;
52	    return row ? toAccount(row) : null;
53	  }
54	
55	  async countActive(): Promise<number> {
56	    const [row] = await this.sql<{ n: number }[]>`
57	      SELECT count(*)::int AS n FROM accounts WHERE archived_at IS NULL`;
58	    return row?.n ?? 0;
59	  }
60	
61	  async insert(account: Account): Promise<Account> {
62	    const r = fromAccount(account);
63	    const [row] = await this.sql<AccountRow[]>`
64	      INSERT INTO accounts (id, name, currency, is_default, archived_at, created_at)
65	      VALUES (${r.id}, ${r.name}, ${r.currency}, ${r.is_default}, ${r.archived_at},
66	              ${r.created_at})
67	      RETURNING *`;
68	    return toAccount(row);
69	  }
70	
71	  async update(account: Account): Promise<Account> {
72	    const r = fromAccount(account);
73	    const [row] = await this.sql<AccountRow[]>`
74	      UPDATE accounts
75	         SET name = ${r.name}, currency = ${r.currency}, is_default = ${r.is_default},
76	             archived_at = ${r.archived_at}
