  constructor(private readonly sql: Sql) {}

  async list(opts?: { includeArchived?: boolean }): Promise<Account[]> {
    const rows = opts?.includeArchived
      ? await this.sql<AccountRow[]>`SELECT * FROM accounts ORDER BY created_at`
      : await this.sql<AccountRow[]>`
          SELECT * FROM accounts WHERE archived_at IS NULL ORDER BY created_at`;
    return rows.map(toAccount);
  }

  async findById(id: string): Promise<Account | null> {
    const [row] = await this.sql<AccountRow[]>`
      SELECT * FROM accounts WHERE id = ${id}`;
    return row ? toAccount(row) : null;
  }

  async findDefault(): Promise<Account | null> {
    const [row] = await this.sql<AccountRow[]>`
      SELECT * FROM accounts WHERE archived_at IS NULL AND is_default LIMIT 1`;
    return row ? toAccount(row) : null;
  }

  async countActive(): Promise<number> {
    const [row] = await this.sql<{ n: number }[]>`
      SELECT count(*)::int AS n FROM accounts WHERE archived_at IS NULL`;
    return row?.n ?? 0;
  }

  async insert(account: Account): Promise<Account> {
    const r = fromAccount(account);
    const [row] = await this.sql<AccountRow[]>`
      INSERT INTO accounts (id, name, currency, is_default, archived_at, created_at)
      VALUES (${r.id}, ${r.name}, ${r.currency}, ${r.is_default}, ${r.archived_at},
              ${r.created_at})
      RETURNING *`;
    return toAccount(row);
  }

  async update(account: Account): Promise<Account> {
    const r = fromAccount(account);
    const [row] = await this.sql<AccountRow[]>`
      UPDATE accounts
         SET name = ${r.name}, currency = ${r.currency}, is_default = ${r.is_default},
             archived_at = ${r.archived_at}
       WHERE id = ${r.id}
      RETURNING *`;
    return toAccount(row);
  }

  async setDefault(id: string): Promise<void> {
    // Clear-all-then-set inside one transaction so the partial-unique index
    // never sees two defaults (D2).
    await this.sql.begin(async (tx) => {
      await tx`UPDATE accounts SET is_default = false WHERE is_default`;
      await tx`UPDATE accounts SET is_default = true WHERE id = ${id}`;
    });
  }
}

class PgInputEventRepository implements InputEventRepository {
  constructor(private readonly sql: Sql) {}

  async create(event: NewInputEvent): Promise<InputEvent> {
    const [row] = await this.sql<InputEventRow[]>`
      INSERT INTO input_events (id, source, provider, raw_text, storage_uri, mime_type)
      VALUES (${event.id ?? globalThis.crypto.randomUUID()}, ${event.source},
              ${event.provider}, ${event.rawText}, ${event.storageUri},
              ${event.mimeType})
      RETURNING *`;
    return toInputEvent(row);
  }

  async findById(id: string): Promise<InputEvent | null> {
    const [row] = await this.sql<InputEventRow[]>`
      SELECT * FROM input_events WHERE id = ${id}`;
    return row ? toInputEvent(row) : null;
  }
}

class PgParserRunRepository implements ParserRunRepository {
  constructor(private readonly sql: Sql) {}

  async create(run: NewParserRun): Promise<ParserRun> {
    const [row] = await this.sql<ParserRunRow[]>`
      INSERT INTO parser_runs (id, input_event_id, status, normalized_payload, result_json, error)
      VALUES (${run.id ?? globalThis.crypto.randomUUID()}, ${run.inputEventId},
              ${run.status}, ${run.normalizedPayload}, ${run.resultJson},
              ${run.error})
      RETURNING *`;
    return toParserRun(row);
  }

  async findById(id: string): Promise<ParserRun | null> {
    const [row] = await this.sql<ParserRunRow[]>`
      SELECT * FROM parser_runs WHERE id = ${id}`;
    return row ? toParserRun(row) : null;
  }
}

class PgLedgerItemRepository implements LedgerItemRepository {
  constructor(private readonly sql: Sql) {}

  async insert(item: LedgerItem): Promise<LedgerItem> {
    const r = fromLedgerItem(item);
    const [row] = await this.sql<LedgerItemRow[]>`
      INSERT INTO ledger_items
        (id, account_id, input_event_id, parser_run_id, description, amount_minor,
         currency, type, category, status, import_row_number, occurred_at)
      VALUES
        (${r.id}, ${r.account_id}, ${r.input_event_id}, ${r.parser_run_id},
         ${r.description}, ${r.amount_minor}, ${r.currency}, ${r.type},
         ${r.category}, ${r.status}, ${r.import_row_number}, ${r.occurred_at})
      RETURNING *`;
    return toLedgerItem(row);
  }

  async findById(id: string): Promise<LedgerItem | null> {
    const [row] = await this.sql<LedgerItemRow[]>`
      SELECT * FROM ledger_items WHERE id = ${id}`;
    return row ? toLedgerItem(row) : null;
  }
}

export function createPostgresRepositories(sql: Sql): Repositories {
  return {
    inputEvents: new PgInputEventRepository(sql),
    parserRuns: new PgParserRunRepository(sql),
    ledgerItems: new PgLedgerItemRepository(sql),
    accounts: new PgAccountRepository(sql),
  };
}

// Accounts screen (FR-ACCT-01/03/04/05/06). Server component: it reads accounts
// through the shared DB boundary and mutates only via the server actions, so the
// DB boundary is never imported into a client bundle (TC-STACK-02). Ukrainian-first
// copy lives in accounts-content.ts; the inline error banner reuses the shared
// states.

import { getRepositories } from "@/src/db/client";
import { AccountsService } from "@/src/modules/accounts/service";
import {
  ACCOUNTS_PAGE,
  accountErrorMessage,
} from "@/src/modules/accounts/ui/accounts-content";
import { PageHeader } from "@/src/modules/foundation/ui/PageHeader";
import { EmptyState, ErrorState } from "@/src/modules/foundation/ui/states";
import {
  archiveAccountAction,
  createAccountAction,
  renameAccountAction,
  setDefaultAccountAction,
} from "./actions";

export const dynamic = "force-dynamic";

export default async function AccountsPage({
  searchParams,
}: {
  searchParams: Promise<{ formError?: string }>;
}) {
  const { formError } = await searchParams;
  const errorMessage = accountErrorMessage(formError);

  const service = new AccountsService(getRepositories().accounts);
  await service.ensureSeededDefault();
  const accounts = await service.listActive();

  return (
    <>
      <PageHeader title={ACCOUNTS_PAGE.title} description={ACCOUNTS_PAGE.description} />

      {errorMessage ? (
        <div className="mb-6">
          <ErrorState title="Дію не виконано" description={errorMessage} />
        </div>
      ) : null}

      <section
        aria-labelledby="accounts-create-heading"
        className="mb-8 rounded-fin border border-fin-border bg-fin-surface p-5 shadow-fin"
      >
        <h2
          id="accounts-create-heading"
          className="mb-3 text-base font-semibold text-fin-fg"
        >
          {ACCOUNTS_PAGE.createHeading}
        </h2>
        <form
          action={createAccountAction}
          className="flex flex-wrap items-end gap-3"
        >
          <label className="flex flex-1 flex-col gap-1 text-sm">
            <span className="text-fin-fg-muted">{ACCOUNTS_PAGE.nameLabel}</span>
            <input
              name="name"
              required
              maxLength={60}
              placeholder={ACCOUNTS_PAGE.namePlaceholder}
              className="min-h-11 rounded-fin border border-fin-border bg-fin-bg px-3 text-fin-fg placeholder:text-fin-fg-subtle focus:border-fin-border-strong focus:outline-none"
            />
          </label>
          <button
            type="submit"
            className="min-h-11 rounded-fin bg-fin-primary px-4 font-medium text-white transition-colors hover:bg-fin-primary-hover"
          >
            {ACCOUNTS_PAGE.createLabel}
          </button>
        </form>
      </section>

      {accounts.length === 0 ? (
        <EmptyState
          title={ACCOUNTS_PAGE.emptyTitle}
          description={ACCOUNTS_PAGE.emptyDescription}
        />
      ) : (
        <ul className="space-y-4">
          {accounts.map((account) => (
            <li
              key={account.id}
              className="rounded-fin border border-fin-border bg-fin-surface p-5 shadow-fin"
            >
              <div className="flex flex-wrap items-center justify-between gap-3">
                <div className="flex items-center gap-2">
                  <span className="text-base font-semibold text-fin-fg">
                    {account.name}
                  </span>
                  <span className="text-xs text-fin-fg-subtle">
                    {account.currency}
                  </span>
                  {account.isDefault ? (
                    <span className="rounded-fin bg-fin-info-bg px-2 py-0.5 text-xs font-medium text-fin-info-fg">
                      {ACCOUNTS_PAGE.defaultBadge}
                    </span>
                  ) : null}
                </div>

                <div className="flex flex-wrap items-center gap-2">
                  {account.isDefault ? null : (
                    <form action={setDefaultAccountAction}>
                      <input type="hidden" name="id" value={account.id} />
                      <button
                        type="submit"
                        className="min-h-11 rounded-fin border border-fin-border px-3 text-sm text-fin-fg transition-colors hover:border-fin-border-strong hover:bg-fin-surface-muted"
                      >
                        {ACCOUNTS_PAGE.setDefaultLabel}
                      </button>
                    </form>
                  )}
                  <form action={archiveAccountAction}>
                    <input type="hidden" name="id" value={account.id} />
                    <button
                      type="submit"
                      className="min-h-11 rounded-fin border border-fin-border px-3 text-sm text-fin-fg-muted transition-colors hover:border-fin-error-border hover:text-fin-error-fg"
                    >
                      {ACCOUNTS_PAGE.archiveLabel}
                    </button>
                  </form>
                </div>
              </div>

              <form
                action={renameAccountAction}
                className="mt-3 flex flex-wrap items-end gap-2"
              >
                <input type="hidden" name="id" value={account.id} />
                <label className="flex flex-1 flex-col gap-1 text-sm">
                  <span className="sr-only">{ACCOUNTS_PAGE.renameLabel}</span>
                  <input
                    name="name"
                    required
                    maxLength={60}
                    defaultValue={account.name}
                    aria-label={`${ACCOUNTS_PAGE.renameLabel}: ${account.name}`}
                    className="min-h-11 rounded-fin border border-fin-border bg-fin-bg px-3 text-fin-fg focus:border-fin-border-strong focus:outline-none"
                  />
                </label>
                <button
                  type="submit"
                  className="min-h-11 rounded-fin border border-fin-border px-3 text-sm text-fin-fg transition-colors hover:border-fin-border-strong hover:bg-fin-surface-muted"
                >
                  {ACCOUNTS_PAGE.renameSubmitLabel}
                </button>
              </form>
            </li>
          ))}
        </ul>
      )}

      <p className="mt-6 text-xs text-fin-fg-subtle">{ACCOUNTS_PAGE.balanceHint}</p>
    </>
  );
}

